// Q1: can we clear the heap on demand inside a workflow?
const mb = b => Math.round(b / 1048576);
const before = process.memoryUsage().heapUsed;
let big = [];
for (let i = 0; i < 800000; i++) big.push({ v: i, s: 'x' + i });
const afterBuild = process.memoryUsage().heapUsed;
big = null;                         // drop the reference
const hasGc = typeof global.gc;     // 'function' only if node started with --expose-gc
if (hasGc === 'function') { global.gc(); }
const afterClear = process.memoryUsage().heapUsed;
return [{ json: {
  hasGlobalGc: hasGc,
  canForceGc: hasGc === 'function',
  heapUsed_before_MB: mb(before),
  heapUsed_afterBuild_MB: mb(afterBuild),
  heapUsed_afterNull_and_gc_MB: mb(afterClear)
} }];
